starter_code:
module top_module(input clk, input rst_n, input din, output detected);
  // TODO
endmodule

solution_code:
module top_module(input clk, input rst_n, input din, output detected);
  localparam S0=0,S1=1,S10=2,S101=3,S1011=4;
  reg [2:0] st;
  always @(posedge clk or negedge rst_n) begin
    if(!rst_n) st<=S0; else case(st)
      S0: st <= din?S1:S0;
      S1: st <= din?S1:S10;
      S10: st <= din?S101:S0;
      S101: st <= din?S1011:S10;
      S1011: st <= din?S1:S10;
      default: st<=S0;
    endcase
  end
  assign detected = (st==S1011);
endmodule

