starter_code:
module top_module #(parameter AW=4)(input clk, input rst_n, input wr, input rd, output full, output empty);
  // TODO
endmodule

solution_code:
module top_module #(parameter AW=4)(input clk, input rst_n, input wr, input rd, output full, output empty);
  reg [AW:0] wptr, rptr;
  always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin wptr<=0; rptr<=0; end
    else begin
      if(wr && !full) wptr<=wptr+1'b1;
      if(rd && !empty) rptr<=rptr+1'b1;
    end
  end
  assign empty = (wptr==rptr);
  assign full = (wptr[AW]!=rptr[AW]) && (wptr[AW-1:0]==rptr[AW-1:0]);
endmodule
